import { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { useAuthStore } from '@/store/useAuthStore'
import { supabase } from '@/lib/supabase'
import { Header } from '@/components/Header'

// Soft-Delete-Flow laut CLAUDE.md §10.
// User klickt "Account löschen" → 30 Tage Recovery-Window → Cron-Job deletet
// nach Ablauf hard. User kann sich bis dahin neu einloggen + reaktivieren.

export default function DeleteAccount() {
  const { user, signOut } = useAuthStore()
  const navigate = useNavigate()
  const [confirm, setConfirm] = useState('')
  const [busy, setBusy] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [deletedAt, setDeletedAt] = useState<string | null>(null)

  useEffect(() => {
    if (!user) return
    void supabase.from('profiles').select('deleted_at').eq('id', user.id).single()
      .then(({ data }) => setDeletedAt((data as { deleted_at: string | null } | null)?.deleted_at ?? null))
  }, [user])

  async function handleDelete() {
    if (!user) return
    setBusy(true)
    setError(null)
    const { error } = await supabase
      .from('profiles')
      .update({ deleted_at: new Date().toISOString() })
      .eq('id', user.id)
    setBusy(false)
    if (error) { setError(error.message); return }
    await signOut()
    navigate('/auth/login', { replace: true })
  }

  async function handleCancel() {
    if (!user) return
    setBusy(true)
    await supabase.from('profiles').update({ deleted_at: null }).eq('id', user.id)
    setDeletedAt(null)
    setBusy(false)
  }

  if (deletedAt) {
    const deleteDate = new Date(new Date(deletedAt).getTime() + 30 * 86400000)
    return (
      <Wrap>
        <div style={{ fontSize: '3rem', textAlign: 'center' }}>⏳</div>
        <h1 className="app-name" style={{ color: 'var(--orange)', textAlign: 'center', margin: 0 }}>
          Löschung geplant
        </h1>
        <p style={{ textAlign: 'center', maxWidth: 380, opacity: 0.75 }}>
          Dein Account wird am <b>{deleteDate.toLocaleDateString('de-DE')}</b> endgültig gelöscht.
          Bis dahin kannst du die Löschung abbrechen.
        </p>
        <button
          onClick={handleCancel}
          disabled={busy}
          style={{ background: 'var(--green)', color: 'var(--cream)', border: 'none', padding: '0.8rem 1.4rem', borderRadius: 10, fontFamily: 'inherit', fontWeight: 700, cursor: 'pointer', opacity: busy ? 0.5 : 1 }}
        >
          {busy ? 'Wird abgebrochen…' : 'Löschung abbrechen'}
        </button>
      </Wrap>
    )
  }

  return (
    <Wrap>
      <div style={{ fontSize: '3rem', textAlign: 'center' }}>⚠️</div>
      <h1 className="app-name" style={{ color: 'var(--red)', textAlign: 'center', margin: 0 }}>
        Account löschen
      </h1>
      <div style={{ background: 'var(--white)', border: '2px solid var(--red)', borderRadius: 14, padding: '1.2rem', boxShadow: 'var(--shadow-card)', maxWidth: 420, width: '100%' }}>
        <p style={{ marginTop: 0, fontSize: '0.9rem', lineHeight: 1.5 }}>
          Dein Account wird in <b>30 Tagen</b> endgültig gelöscht. In diesem Zeitraum kannst du dich
          jederzeit wieder einloggen und die Löschung stornieren.
        </p>
        <p style={{ fontSize: '0.85rem', opacity: 0.7 }}>
          Was gelöscht wird: Profil, Lernfortschritt, Streak, XP, Achievements, alle SRS-Daten.
        </p>
        <p style={{ fontSize: '0.85rem', opacity: 0.7 }}>
          Tippe <b>LÖSCHEN</b> in das Feld, um den Vorgang zu bestätigen.
        </p>
        <input
          type="text"
          value={confirm}
          onChange={(e) => setConfirm(e.target.value.toUpperCase())}
          placeholder="LÖSCHEN"
          style={{ width: '100%', padding: '0.7rem', border: '1.5px solid rgba(0,0,0,0.15)', borderRadius: 8, fontFamily: 'inherit', fontSize: '1rem', marginBottom: 10 }}
        />
        {error && <div style={{ color: 'var(--red)', fontSize: '0.85rem', marginBottom: 8 }}>⚠ {error}</div>}
        <div style={{ display: 'flex', gap: 8 }}>
          <button
            onClick={handleDelete}
            disabled={confirm !== 'LÖSCHEN' || busy}
            style={{ flex: 1, background: 'var(--red)', color: 'var(--cream)', border: 'none', padding: '0.7rem', borderRadius: 10, fontFamily: 'inherit', fontWeight: 700, cursor: confirm === 'LÖSCHEN' && !busy ? 'pointer' : 'default', opacity: confirm === 'LÖSCHEN' && !busy ? 1 : 0.5 }}
          >
            Endgültig löschen (in 30 Tagen)
          </button>
          <button
            onClick={() => navigate('/profile')}
            style={{ background: 'none', border: '2px solid rgba(0,0,0,0.15)', padding: '0.7rem 1rem', borderRadius: 10, fontFamily: 'inherit', fontWeight: 600, cursor: 'pointer' }}
          >
            Zurück
          </button>
        </div>
      </div>
    </Wrap>
  )
}

function Wrap({ children }: { children: React.ReactNode }) {
  return (
    <div style={{ minHeight: '100vh', background: 'var(--cream)', display: 'flex', flexDirection: 'column' }}>
      <Header />
      <main style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '2rem 1rem 4rem', gap: '1.2rem' }}>
        {children}
      </main>
    </div>
  )
}
